// SPDX-License-Identifier: MITpackage databaseimport (	"strings"	"testing")func TestCount_TableAllowlist(t *testing.T) {	db, err := Open(":memory:")	if err != nil {		t.Fatalf("Open failed: %v", err)	}	defer db.Close()	_, err = db.Count("projects", "1=1")	if err != nil && !strings.Contains(err.Error(), "no such table") {		t.Errorf("unexpected error for allowed table 'projects': %v", err)	}	blocked := []string{"sqlite_master", "users", "passwords", "; DROP TABLE projects"}	for _, table := range blocked {		_, err = db.Count(table, "1=1")		if err == nil {			t.Errorf("expected error for blocked table %q", table)		}		if !strings.Contains(err.Error(), "not allowed for count") {			t.Errorf("expected allowlist rejection for table %q, got: %v", table, err)		}	}}func TestCount_WhereClause(t *testing.T) {	db, err := Open(":memory:")	if err != nil {		t.Fatalf("Open failed: %v", err)	}	defer db.Close()	_, err = db.Count("events", "1=1")	if err != nil && !strings.Contains(err.Error(), "no such table") {		t.Errorf("unexpected error for allowed table 'events': %v", err)	}	_, err = db.Count("events", "")	if err == nil {		t.Error("expected error for empty WHERE clause")	}}
